css:
body { text-shadow: 0 0 8px rgba(255, 42, 109, 0.15); }
.header { border-bottom: 2px solid #ff2a6d; box-shadow: 0 2px 20px rgba(255, 42, 109, 0.25); }
a, .artist-link { text-shadow: 0 0 6px rgba(0, 240, 255, 0.4); }
.grid-card { box-shadow: 0 0 15px rgba(255, 42, 109, 0.15), 0 0 30px rgba(0, 240, 255, 0.08); }
.grid-card:hover { box-shadow: 0 0 20px rgba(255, 42, 109, 0.3), 0 0 40px rgba(0, 240, 255, 0.15); }
